  (Server : TCP_Connection;
   Client : out TCP_Connection;
   Result : out Status)

procedure Connect
  (Conn    : in out TCP_Connection;
   Host    : String;
   Port    : Natural := 502;
   Timeout : Duration := 5.0;
   Result  : out Status)

procedure Listen
  (Conn   : in out TCP_Connection;
   Port   : Natural := 502;
   Result : out Status)

function Receive
  (Conn       : in out TCP_Connection;
   Buffer     : out Byte_Array;
   Max_Length : Natural;
   Timeout_Ms : Natural) return Natural

procedure Receive_Frame
  (Conn       : in out TCP_Connection;
   Buffer     : out Byte_Array;
   Length     : out Natural;
   Timeout_Ms : Natural;
   Result     : out Status)

procedure Send_Frame
  (Conn   : in out TCP_Connection;
   Frame  : Byte_Array;
   Result : out Status)
